Rule.Source:
  import sailpoint.object.Identity;
  import sailpoint.object.Application;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  Log logger = LogFactory.getLog("Ascension-Rule-IdentitySelector-UpdateManualTerm");

  logger.debug("Start of rule Ascension-Rule-IdentitySelector-UpdateManualTerm");
  boolean status = false;
  IdentityService idService = new IdentityService(context);

  if(null != identity &&  Util.nullSafeCaseInsensitiveEq(identity.getAttribute("manualTerm") , "yes")){

    Application app = context.getObjectByName(Application.class,"DB-Peoplesoft-HCM-Primary");	
    Application mdstaffApp = context.getObjectByName(Application.class,"MDStaff - AMITA");
    Application morriseyApp = context.getObjectByName(Application.class,"Morrisey");
	Application mdstaffAscApp = context.getObjectByName(Application.class,"MDStaff - Ascension");

    if(null != app && !Util.isEmpty(idService.getLinks( identity, app))){
      status = true;
      //comment decache //context.decache(app);
    }
    else if(null != mdstaffApp && !Util.isEmpty(idService.getLinks( identity, mdstaffApp))){
      status = true;
      //comment decache //context.decache(mdstaffApp);
    }
    else if(null != morriseyApp && !Util.isEmpty(idService.getLinks( identity, morriseyApp))){
      status = true;
      //comment decache //context.decache(morriseyApp);
    }
	else if(null != mdstaffAscApp && !Util.isEmpty(idService.getLinks( identity, mdstaffAscApp))){
      status = true;
      //comment decache //context.decache(mdstaffAscApp);
    }
  }
  logger.debug("Exit of rule Ascension-Rule-IdentitySelector-UpdateManualTerm");

  return status;
